sql:
SELECT SUM(total_weeks_on_chart) AS total_weeks_on_chart
FROM chart_entries
WHERE track_id = 0 AND chart_id = 1;

SELECT platform, stream_count
FROM streaming_data
WHERE track_id = 1 AND platform = 'Apple Music';

